from flask import Flask, request, jsonify, render_template, send_file
import os, shutil, uuid, zipfile

from ocr_to_excel import run

app = Flask(__name__)
UPLOAD_FOLDER = "data/uploads"

os.makedirs(UPLOAD_FOLDER, exist_ok=True)


@app.route("/")
def home():
    return render_template("index.html")


@app.route("/upload", methods=["POST"])
def upload():
    print("🔥 Upload request received")

    files = request.files.getlist("files")

    if not files:
        return jsonify({"error": "No file uploaded"}), 400

    print(f"Files received: {len(files)}")

    # Create working folders
    folder_id = str(uuid.uuid4())
    base_folder = os.path.join(UPLOAD_FOLDER, folder_id)
    patients_folder = os.path.join(base_folder, "patients")

    os.makedirs(patients_folder, exist_ok=True)

    # ✅ Save ZIP
    zip_file = files[0]
    zip_path = os.path.join(base_folder, "patients.zip")
    zip_file.save(zip_path)

    print("📦 ZIP saved")

    # ✅ Extract ZIP
    try:
        with zipfile.ZipFile(zip_path, 'r') as zip_ref:
            zip_ref.extractall(patients_folder)
        print("📦 ZIP extracted")
    except Exception as e:
        return jsonify({"error": f"ZIP extraction failed: {str(e)}"}), 500

    # ✅ Handle nested folder (patients/patients/)
    inner = os.path.join(patients_folder, "patients")
    if os.path.exists(inner):
        patients_folder = inner
        print("📂 Using nested patients folder")

    # ✅ Check if patient folders exist
    subfolders = [f for f in os.listdir(patients_folder)
                  if os.path.isdir(os.path.join(patients_folder, f))]

    if not subfolders:
        return jsonify({"error": "No patient folders found inside ZIP"}), 400

    print(f"📁 Found patients: {subfolders}")

    # Output paths
    output_csv = os.path.join(base_folder, "output.csv")
    output_xlsx = os.path.join(base_folder, "output.xlsx")
    output_json = os.path.join(base_folder, "output.json")

    print("🚀 Starting OCR pipeline...")

    # ✅ Run your pipeline
    run(
        patients_dir=patients_folder,
        output_csv=output_csv,
        output_xlsx=output_xlsx,
        output_json=output_json,
        max_patient_chars=8000,
        model="gemini-2.5-flash"
    )

    print("✅ DONE")

    return jsonify({
        "csv": output_csv,
        "xlsx": output_xlsx,
        "json": output_json
    })


# ✅ Download routes
@app.route("/download/csv")
def download_csv():
    return send_file(request.args.get("path"), as_attachment=True)

@app.route("/download/xlsx")
def download_xlsx():
    return send_file(request.args.get("path"), as_attachment=True)

@app.route("/download/json")
def download_json():
    return send_file(request.args.get("path"), as_attachment=True)


if __name__ == "__main__":
    # 🔥 IMPORTANT: disable auto-reloader
    app.run(debug=True, use_reloader=False)

